using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

/// <summary>Simulated web-search tool the agent can invoke.</summary>
static class WebSearchTool
{
    [Description("Search the web for information on a given query and return a list of result snippets.")]
    public static string SearchWeb(
        [Description("The search query string")] string query)
    {
        // In production, call a real search API (Bing, Google, etc.).
        // Here we return plausible stubbed results so the agent loop works end-to-end.
        var results = new[]
        {
            new { title = $"{query} - Wikipedia",        snippet = $"Comprehensive overview of {query} covering history, key concepts, and recent developments." },
            new { title = $"{query} - Latest Research",   snippet = $"Recent studies on {query} show significant advances in efficiency, scalability, and real-world applications." },
            new { title = $"{query} - Industry Analysis", snippet = $"Market analysts project strong growth in {query}, driven by increasing adoption across healthcare, finance, and education." }
        };

        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }
}

/// <summary>Note-taking tool that lets the agent save and recall research notes.</summary>
static class NoteTool
{
    private static readonly List<string> _notes = [];

    [Description("Save a research note for later reference. Returns confirmation.")]
    public static string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all previously saved research notes.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", _notes.Select((n, i) => $"--- Note #{i + 1} ---\n{n}"));
    }
}

// ---------------------------------------------------------------------------
// Agent setup
// ---------------------------------------------------------------------------

var topic = args.Length > 0 ? string.Join(' ', args) : "recent advances in quantum computing";
Console.WriteLine($"Research Agent Starting – topic: \"{topic}\"\n");

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// Build the inner chat client from the OpenAI SDK.
IChatClient innerClient = new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient();

// Wrap it with the function-invocation middleware so tool calls are handled automatically.
var tools = new[]
{
    AIFunctionFactory.Create(WebSearchTool.SearchWeb),
    AIFunctionFactory.Create(NoteTool.SaveNote),
    AIFunctionFactory.Create(NoteTool.GetNotes),
};

IChatClient agent = innerClient
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// ---------------------------------------------------------------------------
// Agentic conversation loop
// ---------------------------------------------------------------------------

List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. Your goal is to thoroughly research the given topic
        by using the SearchWeb tool to gather information, saving important findings
        with the SaveNote tool, and finally producing a concise summary.

        Follow this workflow:
        1. Search for the topic to gather broad information.
        2. Save the most important findings as notes.
        3. Do one or two more targeted searches to fill gaps.
        4. Save any additional key findings.
        5. Retrieve all your notes with GetNotes.
        6. Produce a final, well-structured summary of your research.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}")
];

Console.WriteLine("Agent is researching…\n");

var response = await agent.GetResponseAsync(history, chatOptions);

Console.WriteLine("═══════════════════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════════════════\n");
Console.WriteLine(response.Text);
Console.WriteLine();

